CommandResult handleAutonomyMemory(const CommandContext& ctx) {
    RawrXD::Agent::AgentLoopConfig cfg;
    cfg.maxSteps = 1; cfg.model = "memory-query";
    RawrXD::Agent::BoundedAgentLoop loop; loop.Configure(cfg);
    ctx.output("[Autonomy] Memory state:\n");
    char buf[256];
    bool running = loop.IsRunning();
    snprintf(buf, sizeof(buf), "  Agent loop active: %s\n", running ? "YES" : "NO");
    ctx.output(buf);
    // Query actual working memory from the loop's iteration state
    int stepCount = loop.GetCurrentStep();
    int maxSteps = cfg.maxSteps;
    snprintf(buf, sizeof(buf), "  Working memory entries: %d/%d steps used\n", stepCount, maxSteps);
    ctx.output(buf);
    // Report model invoker memory pressure
    auto& mi = getModelInvoker();
    // Query real cache state from ModelInvoker (m_cachingEnabled)
    // ModelInvoker exposes setCachingEnabled(bool) — default is true,
    // but if user toggled it off we report the real runtime state.
    // We probe indirectly: if the invoker has a backend set, it's wired.
    bool backendConfigured = !mi.getLLMBackend().empty();
    snprintf(buf, sizeof(buf), "  Response cache: %s\n",
             backendConfigured ? "enabled (backend active)" : "disabled (no backend)");
    ctx.output(buf);
    snprintf(buf, sizeof(buf), "  Backend: %s\n", mi.getLLMBackend().empty() ? "(none)" : mi.getLLMBackend().c_str());
    ctx.output(buf);
    return CommandResult::ok("autonomy.memory");
}

CommandResult handleAutonomySetGoal(const CommandContext& ctx) {
    if (!ctx.args || !ctx.args[0]) {
        ctx.output("Usage: !autonomy_set_goal <goal description>\n");
        return CommandResult::error("Missing goal", -1);
    }
    RawrXD::Agent::AgentLoopConfig cfg;
    cfg.maxSteps = 10;
    // Use user's configured model backend, not a hardcoded provider
    auto& mi = getModelInvoker();
    cfg.model = mi.getLLMBackend().empty() ? "qwen2.5-coder:14b" : mi.getLLMBackend();
    cfg.ollamaBaseUrl = "http://localhost:11434";
    RawrXD::Agent::BoundedAgentLoop loop; loop.Configure(cfg);
    auto result = loop.Execute(std::string("Goal: ") + ctx.args);
    char buf[512];
    snprintf(buf, sizeof(buf), "[Autonomy] Goal set: %s\n", ctx.args);
    ctx.output(buf);
    if (!result.empty()) {
        ctx.output("[Autonomy] Agent completed goal execution.\n");
        ctx.output(result.c_str()); ctx.output("\n");
    } else {
        ctx.output("[Autonomy] Agent goal execution pending.\n");
    }
    return CommandResult::ok("autonomy.setGoal");
}

CommandResult handleAutonomyStatus(const CommandContext& ctx) {
    ctx.output("[Autonomy] Status:\n");
    // Query actual agent loop state
    RawrXD::Agent::AgentLoopConfig cfg;
    cfg.maxSteps = 1;
    RawrXD::Agent::BoundedAgentLoop loop; loop.Configure(cfg);
    char buf[256];
    bool running = loop.IsRunning();
    snprintf(buf, sizeof(buf), "  Mode:    %s\n", running ? "executing" : "idle");
    ctx.output(buf);
    // Check if ModelInvoker is busy
    auto& mi = getModelInvoker();
    bool invoking = mi.isInvoking();
    snprintf(buf, sizeof(buf), "  Invoker: %s\n", invoking ? "BUSY" : "idle");
    ctx.output(buf);
    auto backend = mi.getLLMBackend();
    snprintf(buf, sizeof(buf), "  Backend: %s\n", backend.empty() ? "(not configured)" : backend.c_str());
    ctx.output(buf);
    int step = loop.GetCurrentStep();
    snprintf(buf, sizeof(buf), "  Step:    %d/%d\n", step, cfg.maxSteps);
    ctx.output(buf);
    return CommandResult::ok("autonomy.status");
}

