        snprintf(buf, sizeof(buf), "[LSP] Server already running (diag=%llu, rebuilds=%llu)\n",
                 (unsigned long long)stats.diagnosticRefreshes.load(),
                 (unsigned long long)stats.symbolRebuilds.load());
        ctx.output(buf);
